PythonJavaGo <pre><code>from confluent_kafka import Producer, Consumer, KafkaError
import json
import logging

logger = logging.getLogger(__name__)

class OrderEventProducer:
    def __init__(self, bootstrap_servers: str, topic: str):
        self.topic = topic
        self.producer = Producer({
            'bootstrap.servers': bootstrap_servers,
            'acks': 'all',
            'enable.idempotence': True,
            'retries': 3,
        })

    def publish(self, user_id: str, event: dict) -&gt; None:
        value = json.dumps(event).encode('utf-8')
        self.producer.produce(
            topic=self.topic,
            key=user_id.encode('utf-8'),
            value=value,
            callback=self._delivery_callback,
        )
        self.producer.flush()

    @staticmethod
    def _delivery_callback(err, msg):
        if err:
            logger.error(f"Delivery failed: {err}")
        else:
            logger.info(f"Delivered to {msg.topic()}[{msg.partition()}] @ offset {msg.offset()}")

class OrderEventConsumer:
    def __init__(self, bootstrap_servers: str, group_id: str, topic: str):
        self.consumer = Consumer({
            'bootstrap.servers': bootstrap_servers,
            'group.id': group_id,
            'auto.offset.reset': 'earliest',
            'enable.auto.commit': False,
        })
        self.consumer.subscribe([topic])
        self._running = True

    def consume(self, process_fn):
        while self._running:
            msg = self.consumer.poll(timeout=1.0)
            if msg is None:
                continue
            if msg.error():
                if msg.error().code() == KafkaError._PARTITION_EOF:
                    continue
                logger.error(f"Consumer error: {msg.error()}")
                continue

            try:
                event = json.loads(msg.value().decode('utf-8'))
                process_fn(msg.key().decode('utf-8'), event)
                self.consumer.commit(asynchronous=False)
            except Exception as e:
                logger.error(f"Processing failed: {e}, sending to DLQ")

    def shutdown(self):
        self._running = False
        self.consumer.close()
