        return [p for p, _ in self.ring]

    def node_for_key(self, key: str) -&gt; str:
        if not self.ring:
            raise RuntimeError("empty ring")
        h = self._hash(key)
        positions = self._ring_positions()
        idx = bisect.bisect_right(positions, h) % len(positions)
        return self.ring[idx][1]
