public final class ConsistentHashRing {
    private final TreeMap&lt;Long, String&gt; ring = new TreeMap&lt;&gt;();

    public ConsistentHashRing(List&lt;String&gt; nodes, int vnodes) throws Exception {
        for (String n : nodes) {
            for (int i = 0; i &lt; vnodes; i++) {
                long h = hash(n + ":" + i);
                ring.put(h, n);
            }
        }
    }

