    key := fmt.Sprintf("feed:%s", userID)
    opt := &amp;redis.ZRangeBy{
        Min:   "-inf",
        Max:   fmt.Sprintf("(%f", maxExclusive),
        Count: int64(limit),
    }
    return m.Rdb.ZRevRangeByScore(ctx, key, opt).Result()
