def merge_by_score(streams: Iterable[List[tuple[str, float]]], limit: int) -&gt; List[str]:
    heap: List[tuple[float, int, str, int]] = []
    arrays = [list(s) for s in streams]
    for i, arr in enumerate(arrays):
        if arr:
            pid, sc = arr.pop()
            heapq.heappush(heap, (-sc, i, pid, 0))
    out: List[str] = []
    seen: Set[str] = set()
    while heap and len(out) &lt; limit:
        neg_sc, idx, pid, _ = heapq.heappop(heap)
        if pid not in seen:
            seen.add(pid)
            out.append(pid)
        if arrays[idx]:
            nxt, sc = arrays[idx].pop()
            heapq.heappush(heap, (-sc, idx, nxt, 0))
    return out
